class Solution:
    def longestSubsequence(self, nums):
        n = len(nums)
        best = 0
        for mask in range(1, 1 << n):
            indices = [i for i in range(n) if mask & (1 << i)]
            vals = [nums[i] for i in indices]
            if all(vals[i] < vals[i + 1] for i in range(len(vals) - 1)):
                and_val = vals[0]
                for v in vals[1:]:
                    and_val &= v
                if and_val != 0:
                    best = max(best, len(vals))
        return best

