import bisect

class Solution:
    def longestSubsequence(self, nums):
        BITS = 30
        best = 0
        for b in range(BITS):
            mask = 1 << b
            tails = []
            for x in nums:
                if x & mask:
                    idx = bisect.bisect_left(tails, x)
                    if idx == len(tails):
                        tails.append(x)
                    else:
                        tails[idx] = x
            best = max(best, len(tails))
        return best

