var longestSubsequence = function(nums) {
    const BITS = 30;
    let best = 0;
    for (let b = 0; b < BITS; b++) {
        const mask = 1 << b;
        const tails = [];
        for (const x of nums) {
            if (x & mask) {
                let lo = 0, hi = tails.length;
                while (lo < hi) {
                    const mid = (lo + hi) >> 1;
                    if (tails[mid] < x) lo = mid + 1; else hi = mid;
                }
                if (lo === tails.length) tails.push(x); else tails[lo] = x;
            }
        }
        best = Math.max(best, tails.length);
    }
    return best;
};
